import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  Button,
  DateRangeFilter,
  dispatchAppToast,
  LinListTableConfigModal,
  LinPageLayout,
  loadErpListTableConfig,
  saveErpListTableConfig,
  Select,
  useCatalogTableBusy,
  type DateRangeValue,
  type ErpListTableConfig,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { reportPageLabels } from '../../../constants/reportPageLabels';
import { formatDate, formatVnd } from '../../../utils/formatters';
import { exportExcel, monthStartEnd } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { AccountDto, AccountSummaryRow, GeneralLedgerRow } from '../../../services/analytics/models';

const labels = reportPageLabels.soCai;
const TEST_ID = 'erp-so-cai';
const PAGE_ID = 'baocao-so-cai';

const SoCaiPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { fromDate: iF, toDate: iT } = monthStartEnd();
  const [fromDate, setFromDate] = useState(iF);
  const [toDate, setToDate] = useState(iT);
  const [tab, setTab] = useState<'summary' | 'ledger'>('summary');
  const [accountCode, setAccountCode] = useState('');
  const [accounts, setAccounts] = useState<AccountDto[]>([]);
  const [summary, setSummary] = useState<AccountSummaryRow[]>([]);
  const [ledger, setLedger] = useState<GeneralLedgerRow[]>([]);
  const [loading, setLoading] = useState(false);
  const [accountError, setAccountError] = useState<string | undefined>();
  const [configOpen, setConfigOpen] = useState(false);
  const [tableConfig, setTableConfig] = useState<ErpListTableConfig>(() =>
    loadErpListTableConfig(`${TEST_ID}-report-table-config`),
  );
  const { showTableLoading } = useCatalogTableBusy(loading);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      analyticsService
        .getAccounts({ isDetail: true })
        .then(d => {
          if (!cancelled) setAccounts(d);
        })
        .catch(() => {});
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, []);

  const validateFilters = useCallback((): boolean => {
    if (tab === 'ledger' && !accountCode.trim()) {
      setAccountError(labels.accountRequired);
      dispatchAppToast(dispatch, { message: labels.filterValidationSummary, type: 'warning' });
      return false;
    }
    setAccountError(undefined);
    return true;
  }, [tab, accountCode, dispatch]);

  const handleLoad = useCallback(() => {
    if (!validateFilters()) return;
    setLoading(true);
    const p = { fromDate, toDate, accountCode: accountCode || undefined };
    const req =
      tab === 'summary'
        ? analyticsService.getAccountSummary(p)
        : accountCode
          ? analyticsService.getGeneralLedger(p)
          : Promise.resolve([] as GeneralLedgerRow[]);
    req
      .then(d => {
        if (tab === 'summary') setSummary(d as AccountSummaryRow[]);
        else setLedger(d as GeneralLedgerRow[]);
      })
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, labels.loadError),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [tab, fromDate, toDate, accountCode, dispatch, validateFilters]);

  const handleSaveTableConfig = (next: ErpListTableConfig) => {
    setTableConfig(next);
    saveErpListTableConfig(`${TEST_ID}-report-table-config`, next);
  };

  const rows = tab === 'summary' ? summary : ledger;
  const hasData = rows.length > 0;

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-dateRange`,
        content: (
          <div className={erp.field}>
            <DateRangeFilter
              label="Thời gian"
              fullWidth
              testId={`${TEST_ID}-date-range`}
              fromDate={fromDate}
              toDate={toDate}
              onChange={(v: DateRangeValue) => {
                setFromDate(v.fromDate ?? '');
                setToDate(v.toDate ?? '');
              }}
            />
          </div>
        ),
      },
      {
        testId: `${TEST_ID}-field-account`,
        content: (
          <div className={erp.field}>
            <Select
              label={labels.fieldAccount}
              value={accountCode}
              error={accountError}
              onChange={e => {
                setAccountError(undefined);
                setAccountCode(e.target.value);
              }}
              options={[
                { value: '', label: labels.accountPlaceholder },
                ...accounts.map(a => ({ value: a.code, label: `${a.code} — ${a.name}` })),
              ]}
              size="small"
            />
          </div>
        ),
      },
      {
        testId: `${TEST_ID}-view-btn`,
        content: (
          <Button
            variant="primary"
            onClick={handleLoad}
            loading={loading}
            data-testid={`${TEST_ID}-view-btn`}
          >
            {labels.view}
          </Button>
        ),
      },
    ],
    [fromDate, toDate, accountCode, accountError, accounts, handleLoad, loading],
  );

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: handleLoad,
      canChart: hasData,
      onChart: () =>
        dispatchAppToast(dispatch, { message: labels.chartComingSoon, type: 'info' }),
      canPrint: hasData,
      onPrint: () => window.print(),
      onExport: hasData
        ? () =>
            exportExcel(
              tab === 'summary'
                ? '/accounting/account-summary/export-excel'
                : '/accounting/general-ledger/export-excel',
              { fromDate, toDate, accountCode: accountCode || undefined },
              `SoCai-${fromDate}.xlsx`,
            )
        : undefined,
      onEditConfig: () => setConfigOpen(true),
    }),
    [handleLoad, hasData, dispatch, tab, fromDate, toDate, accountCode],
  );

  const listBody = (
    <>
      <div className={reportStyles.tabs} data-testid={`${TEST_ID}-tabs`}>
        <button
          type="button"
          className={tab === 'summary' ? reportStyles.tabActive : reportStyles.tab}
          onClick={() => setTab('summary')}
        >
          {labels.tabSummary}
        </button>
        <button
          type="button"
          className={tab === 'ledger' ? reportStyles.tabActive : reportStyles.tab}
          onClick={() => setTab('ledger')}
        >
          {labels.tabLedger}
        </button>
      </div>
      {!showTableLoading && rows.length === 0 ? (
        <div
          className={`${erp.empty} ${reportStyles.emptyFill}`}
          data-testid={`${TEST_ID}-empty`}
        >
          {labels.empty}
        </div>
      ) : !showTableLoading ? (
        <div className={reportStyles.tableWrapper}>
          <table className={reportStyles.table} data-testid={`${TEST_ID}-grid`}>
            <thead>
              <tr>
                {tab === 'summary' ? (
                  <>
                    <th>TK</th>
                    <th>Tên</th>
                    <th className={reportStyles.colRight}>Nợ ĐK</th>
                    <th className={reportStyles.colRight}>Có ĐK</th>
                    <th className={reportStyles.colRight}>PS Nợ</th>
                    <th className={reportStyles.colRight}>PS Có</th>
                    <th className={reportStyles.colRight}>Nợ CK</th>
                    <th className={reportStyles.colRight}>Có CK</th>
                  </>
                ) : (
                  <>
                    <th>Ngày</th>
                    <th>Số CT</th>
                    <th>Diễn giải</th>
                    <th className={reportStyles.colRight}>Nợ</th>
                    <th className={reportStyles.colRight}>Có</th>
                    <th className={reportStyles.colRight}>Số dư</th>
                  </>
                )}
              </tr>
            </thead>
            <tbody>
              {tab === 'summary'
                ? summary.map((r, i) => (
                    <tr key={i}>
                      <td>{r.code}</td>
                      <td>{r.name}</td>
                      <td className={reportStyles.colRight}>{formatVnd(r.openingDebit)}</td>
                      <td className={reportStyles.colRight}>{formatVnd(r.openingCredit)}</td>
                      <td className={reportStyles.colRight}>{formatVnd(r.periodDebit)}</td>
                      <td className={reportStyles.colRight}>{formatVnd(r.periodCredit)}</td>
                      <td className={reportStyles.colRight}>{formatVnd(r.closingDebit)}</td>
                      <td className={reportStyles.colRight}>{formatVnd(r.closingCredit)}</td>
                    </tr>
                  ))
                : ledger.map((r, i) => (
                    <tr key={i}>
                      <td>{formatDate(r.voucherDate)}</td>
                      <td>{r.voucherNumber}</td>
                      <td>{r.description ?? '—'}</td>
                      <td className={reportStyles.colRight}>{formatVnd(r.debitAmount)}</td>
                      <td className={reportStyles.colRight}>{formatVnd(r.creditAmount)}</td>
                      <td className={reportStyles.colRight}>{formatVnd(r.balance)}</td>
                    </tr>
                  ))}
            </tbody>
          </table>
        </div>
      ) : null}
    </>
  );

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-report-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-book-open',
          pageId: PAGE_ID,
        }}
        reportToolbar={reportToolbar}
        listTitle={labels.listTitle}
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={8}
        modals={(
          <LinListTableConfigModal
            isOpen={configOpen}
            onClose={() => setConfigOpen(false)}
            testIdPrefix={TEST_ID}
            config={tableConfig}
            onSave={handleSaveTableConfig}
          />
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default SoCaiPage;
